#include <QPainter>
#include <QPaintEvent>

#include "text_palette.h"

TextPalette::TextPalette(QWidget *parent)
    : QWidget(parent)
{
    QPalette pal = palette();

    setPalette(pal);
}

void TextPalette::update_grid()
{
    if (draw_grid)
    {
        draw_grid = false;
    }
    else
    {
        draw_grid = true;
    }

    update();
}

